What does this program print?

```cpp
#include <array>
#include <iostream>

enum class Planet { Mercury, Venus, Earth, Mars, Count };

constexpr std::size_t idx(Planet p) {
    return static_cast<std::size_t>(p);
}

int main() {
    std::array<int, idx(Planet::Count)> dist{ 58, 108, 150, 228 };
    std::cout << dist[idx(Planet::Earth)] << '\n';
}
```

